ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  fullName: payload.lastName ++ " " ++ payload.firstName,
  isAdult: (payload.age default 0) >= 18,
  dept: upper(payload.department default ""),
  processedAt: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"}
}

%dw 2.0
output application/json
var orders = payload.orders default []
var totalAmount = orders reduce ((o, acc = 0) -> acc + (o.qty * o.price))
var byRegion = orders groupBy $.region mapObject ((items, region) ->
    (region): items reduce ((o, acc = 0) -> acc + (o.qty * o.price))
)
var itemTotals = orders groupBy $.item mapObject ((items, item) ->
    (item): items reduce ((o, acc = 0) -> acc + (o.qty * o.price))
)
var topItems = itemTotals pluck ((v, k) -> {item: k as String, total: v})
    orderBy -$.total
---
{
  summary: {
    totalAmount: totalAmount,
    orderCount: sizeOf(orders),
    avgPrice: if (sizeOf(orders) > 0) totalAmount / sizeOf(orders) else 0,
    byRegion: byRegion,
    topItems: topItems[0 to 4]
  },
  normalized: orders map ((o) -> {
    orderId: o.id,
    product: upper(o.item default ""),
    quantity: o.qty,
    unitPrice: o.price,
    lineTotal: o.qty * o.price,
    region: o.region,
    isLargeOrder: (o.qty * o.price) > 500
  }) filter $.isLargeOrder
}

%dw 2.0
output application/json
var ms = attributes.queryParams.ms default "0"
var start = now() as Number {unit: "milliseconds"}
var waited = java!bench_target::SysUtil::sleep(ms as Number)
---
{ok: true, requestedMs: ms as Number, elapsedMs: now() as Number {unit: "milliseconds"} - start}

%dw 2.0
output application/json
var products = payload map ((r) -> {
  id: r.PRODUCT_ID, name: r.PRODUCT_NAME, productType: r.PRODUCT_TYPE,
  unit: r.UNIT, price: r.UNIT_PRICE, active: r.IS_ACTIVE
})
var byType = products groupBy $.productType
var typeSummary = byType mapObject ((items, t) -> (t): {
  count: sizeOf(items),
  avgPrice: (items reduce ((p, acc=0) -> acc + (p.price default 0))) / sizeOf(items),
  maxPrice: max(items map $.price)
})
---
{
  totalProducts: sizeOf(products),
  activeCount: sizeOf(products filter $.active == "1"),
  byType: typeSummary,
  products: products
}

%dw 2.0
output application/json
var users = payload
var byDomain = users groupBy ((u) -> (u.EMAIL default "" splitBy "@")[1] default "unknown")
var domainCounts = byDomain mapObject ((items, domain) -> (domain): sizeOf(items))
---
{
  count: sizeOf(users),
  region: vars.region,
  emailDomains: domainCounts,
  newest: if (sizeOf(users) > 0) (users orderBy $.NAME)[-1].NAME else null,
  oldest: if (sizeOf(users) > 0) (users orderBy $.NAME)[0].NAME else null,
  users: users map {
    id: $.ID,
    name: $.NAME,
    email: $.EMAIL,
    region: $.REGION
  }
}

db:insert.db:input-parameters:
#[{
                        item: payload.item default "unknown",
                        qty: payload.qty default 1,
                        price: payload.price default 0
                    }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
var accounts = payload map ((a) -> {
  id: a.Id, name: a.Name, industry: a.Industry,
  accountType: a."Type", city: a.BillingCity, country: a.BillingCountry,
  employees: a.NumberOfEmployees, revenue: a.AnnualRevenue
})
var byIndustry = accounts groupBy ($.industry default "Unknown")
var industrySummary = byIndustry mapObject ((items, ind) -> (ind): {
  count: sizeOf(items),
  totalEmployees: items reduce ((a, acc=0) -> acc + (a.employees default 0)),
  totalRevenue: items reduce ((a, acc=0) -> acc + (a.revenue default 0))
})
---
{
  totalAccounts: sizeOf(accounts),
  byIndustry: industrySummary,
  accounts: accounts
}

db:execute-script.db:sql:
INSERT INTO perf_users (name, email, region) SELECT 'User_JP_' || LEVEL, 'user' || LEVEL || '@example.jp', 'JP' FROM DUAL CONNECT BY LEVEL <= 50;
INSERT INTO perf_users (name, email, region) SELECT 'User_US_' || LEVEL, 'user' || LEVEL || '@example.com', 'US' FROM DUAL CONNECT BY LEVEL <= 50;
INSERT INTO perf_users (name, email, region) SELECT 'User_EU_' || LEVEL, 'user' || LEVEL || '@example.eu', 'EU' FROM DUAL CONNECT BY LEVEL <= 50
